mapper.select:
/* DisMgmtMapper.selectDisListExcel */ SELECT DIS.PRMT_ID AS PRMT_ID ,DIS.PRMT_NM AS PRMT_NM ,TO_CHAR(TO_DATE(DIS.STRT_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS STRT_DTTM ,TO_CHAR(TO_DATE(DIS.END_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS END_DTTM ,DIS.CHNL_TP AS CHNL_TP ,FN_GET_CODENM('CMN0090', DIS.CHNL_TP) AS CHNL_NM ,DIS.EVNT_CD AS EVNT_CD ,FN_GET_CODENM('CMN0091', DIS.EVNT_CD) AS EVNT_NM ,DIS.SLS_TP AS SLS_TP ,FN_GET_CODENM('CMN0093', DIS.SLS_TP) AS SLS_NM ,DIS.INTM_YN AS INTM_YN ,DIS.MODEL_ID AS MODEL_ID ,DIS.MODEL_NM AS MODEL_NM ,DIS.ENGG_SRL AS ENGG_SRL ,CASE WHEN DIS.ENGG_SRL LIKE '%00%' THEN 'Y' ELSE 'N' END AS ENGG_CNT0 ,CASE WHEN DIS.ENGG_SRL LIKE '%12%' THEN 'Y' ELSE 'N' END AS ENGG_CNT12 ,CASE WHEN DIS.ENGG_SRL LIKE '%18%' THEN 'Y' ELSE 'N' END AS ENGG_CNT18 ,CASE WHEN DIS.ENGG_SRL LIKE '%24%' THEN 'Y' ELSE 'N' END AS ENGG_CNT24 ,CASE WHEN DIS.ENGG_SRL LIKE '%30%' THEN 'Y' ELSE 'N' END AS ENGG_CNT30 ,CASE WHEN DIS.ENGG_SRL LIKE '%36%' THEN 'Y' ELSE 'N' END AS ENGG_CNT36 ,DIS.USG_YN AS USG_YN ,DIS.REGST_ID AS REGST_ID ,FN_GET_USRNM(DIS.REGST_ID) AS REGST_NM ,TO_CHAR(DIS.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM ,DIS.RVISN_ID AS RVISN_ID ,FN_GET_USRNM(DIS.RVISN_ID) AS RVISN_NM ,TO_CHAR(DIS.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MSP_DIS_MST DIS WHERE #{searchBaseDate} BETWEEN SUBSTR(DIS.STRT_DTTM, 1, 8) AND SUBSTR(DIS.END_DTTM, 1, 8)
AND UPPER(DIS.PRMT_NM) LIKE '%' || UPPER( #{searchPrmtNm} ) || '%'
AND DIS.CHNL_TP = #{searchChnlTp}
AND DIS.EVNT_CD = #{searchEvntCd}
AND DIS.SLS_TP = #{searchSlsTp}
AND DIS.USG_YN = 'Y' ORDER BY DIS.PRMT_ID DESC
